// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;


/*
   Key Features of our smart contract (Blockchain-Based Digital Forensics Evidence Chain of Custody):
    1. Add new evidence  
    2. Transfer evidence custody  
    3. Retrieve evidence details  
    4. View complete custody log  
*/

contract ChainOfCustody {
    struct Evidence {
        string evidenceId;              // Unique ID for the evidence
        string description;             // Short description of the evidence
        address currentHolder;          // Address of current custodian
        uint256 timestamp;              // When the evidence was added in system
    }

    mapping(string => Evidence) private evidences;          // To store each evidence using evidenceId as the key
    mapping(string => string[]) private evidenceLog;        // To maintain a complete activity log per evidence

    event EvidenceAdded(string evidenceId, string description, address addedBy, uint256 timestamp);
    event EvidenceTransferred(string evidenceId, address from, address to, uint256 timestamp);

// Function 1: Add New Evidence
    function addEvidence(string memory _evidenceId, string memory _description) public { 

    // Check if evidence with this ID already exists, If yes, we block it so people don't overwrite records
        require(evidences[_evidenceId].timestamp == 0, "Evidence already exists"); 

    // Create new evidenc
        evidences[_evidenceId] = Evidence({
            evidenceId: _evidenceId,
            description: _description,
            currentHolder: msg.sender,           // The creator becomes the first holder
            timestamp: block.timestamp
        });

    // Store activity in log        
        evidenceLog[_evidenceId].push(
            string(
                abi.encodePacked("Added by: ", toAsciiString(msg.sender), " at ", uint2str(block.timestamp))
            )
        );

        emit EvidenceAdded(_evidenceId, _description, msg.sender, block.timestamp);
    }
// Function 2: Transfer Evidence Custody (Only the current holder of the evidence can transfer)
    function transferEvidence(string memory _evidenceId, address _newHolder) public {

    // Ensure evidence exists    
        require(evidences[_evidenceId].timestamp != 0, "Evidence does not exist");

    // Ensure msg.sender is the current holder    
        require(evidences[_evidenceId].currentHolder == msg.sender, "You are not the current holder");

    // Store previous holder for logging
        address prevHolder = evidences[_evidenceId].currentHolder;

    // Update new evidence holder    
        evidences[_evidenceId].currentHolder = _newHolder;


    // Add entry to the evidence activity log
        evidenceLog[_evidenceId].push(
            string(
                abi.encodePacked("Transferred from: ", toAsciiString(prevHolder),
                                 " to: ", toAsciiString(_newHolder),
                                 " at ", uint2str(block.timestamp))
            )
        );

        emit EvidenceTransferred(_evidenceId, prevHolder, _newHolder, block.timestamp);
    }

// Function 3: View Evidence Details
    function getEvidence(string memory _evidenceId) 
        public 
        view 
        returns (string memory, string memory, address, uint256) 
    {
        require(evidences[_evidenceId].timestamp != 0, "Evidence not found");

        Evidence memory e = evidences[_evidenceId];
        return (e.evidenceId, e.description, e.currentHolder, e.timestamp);
    }

// Function 4: View Evidence Activity Log
    function getEvidenceLog(string memory _evidenceId) 
        public 
        view 
        returns (string[] memory) 
    {
        return evidenceLog[_evidenceId];
    }

// Converts Ethereum address to ASCII hex string
    function toAsciiString(address x) private pure returns (string memory) {
        bytes memory s = new bytes(42);
        s[0] = "0";
        s[1] = "x";

    // This loop breaks the address into bytes and turns each byte into a readable hex character.
        for (uint256 i = 0; i < 20; i++) {
            bytes1 b = bytes1(uint8(uint(uint160(x)) / (2**(8*(19 - i)))));
            bytes1 high = bytes1(uint8(b) / 16);
            bytes1 low = bytes1(uint8(b) - 16 * uint8(high));
            s[2 + 2*i] = char(high);
            s[3 + 2*i] = char(low);
        }
        return string(s);
    }

// Converts a byte to a hex character
    function char(bytes1 b) private pure returns (bytes1 c) {
        if (uint8(b) < 10) return bytes1(uint8(b) + 0x30);
        else return bytes1(uint8(b) + 0x57);
    }

// Convert uint → string (for timestamps)
    function uint2str(uint256 _i) internal pure returns (string memory _uintAsString) {
        if (_i == 0) return "0";
        uint256 j = _i;
        uint256 len;

    // Count how many digits the number has.
        while (j != 0) {            
            len++;  
            j /= 10;
        }

    // Fill bytes array with digits
        bytes memory bstr = new bytes(len);
        uint256 k = len;
        while (_i != 0) {
            k = k - 1;
            uint8 temp = uint8(48 + (_i % 10));
            bstr[k] = bytes1(temp);
            _i /= 10;
        }
        return string(bstr);
    }
}
